module.render:
const color = args.color || 'var(--accent-color)';
const vars = [`--mx-color:${color};`];
const gap = args.gap && String(args.gap).trim();
const radius = args.radius && String(args.radius).trim();
const minh = args.minHeight && String(args.minHeight).trim();
const fillN = parseFloat(args.fill);
if (gap) vars.push(`--mx-gap:${gap};`);
if (radius) vars.push(`--mx-radius:${radius};`);
if (minh) vars.push(`--mx-minh:${minh};`);
if (Number.isFinite(fillN)) {
  const f = Math.max(0, Math.min(100, fillN));
  vars.push(`--mx-fill:${f}%;`);
  vars.push(`--mx-fill0:${Math.min(100, f * 2)}%;`);
}
const cells = sections.slice(0, 4).map((s) => (s || '').trim());
while (cells.length < 4) cells.push('');
const cell = (c, i) => `<div class="mdp-mx-cell mdp-mx-c${i}">\n\n${c}\n\n</div>`;
const lbl = (v, cls) => v ? `<div class="${cls}">\n\n${v}\n\n</div>` : `<div class="${cls}"></div>`;
return `\n\n<div class="mdp-mod-matrix" style="${vars.join('')}">` +
  lbl(args.yLabel, 'mdp-mx-ylabel') +
  `<div class="mdp-mx-yends"><span>${(args.yHigh || '')}</span><span>${(args.yLow || '')}</span></div>` +
  `<div class="mdp-mx-grid">${cells.map(cell).join('')}</div>` +
  `<div class="mdp-mx-xends"><span>${(args.xLow || '')}</span><span>${(args.xHigh || '')}</span></div>` +
  lbl(args.xLabel, 'mdp-mx-xlabel') +
  `</div>\n\n`;
